def build_sales_order_pipeline(filters):
    so_filters = {}
    if filters.get("company"):
        so_filters["company"] = filters.get("company")
    if filters.get("customer"):
        so_filters["customer"] = filters.get("customer")
    if filters.get("sales_order"):
        so_filters["name"] = filters.get("sales_order")
    if filters.get("so_status"):
        so_filters["status"] = filters.get("so_status")
    if filters.get("from_date") and filters.get("to_date"):
        so_filters["transaction_date"] = ["between", [filters.get("from_date"), filters.get("to_date")]]

    sales_orders = frappe.get_all(
        "Sales Order",
        filters=so_filters,
        fields=["name", "transaction_date", "customer", "status", "delivery_status", "billing_status", "company"],
        order_by="transaction_date desc, name desc",
        limit_page_length=50000,
    )

    so_names = [s.get("name") for s in sales_orders if s.get("name")]
    if not so_names:
        return []

    work_orders = frappe.get_all(
        "Work Order",
        filters={"sales_order": ["in", so_names]},
        fields=["name", "sales_order", "production_plan", "status", "qty", "produced_qty"],
        limit_page_length=100000,
    )
    wo_names = [w.get("name") for w in work_orders if w.get("name")]

    job_cards = []
    if wo_names:
        job_cards = frappe.get_all(
            "Job Card",
            filters={"work_order": ["in", wo_names]},
            fields=["name", "work_order", "status", "operation"],
            limit_page_length=200000,
        )

    stock_entries = []
    if wo_names:
        stock_entries = frappe.get_all(
            "Stock Entry",
            filters={"work_order": ["in", wo_names], "docstatus": ["!=", 2]},
            fields=["name", "work_order", "stock_entry_type", "docstatus"],
            limit_page_length=200000,
        )

    wo_by_so = {}
    for w in work_orders:
        so = w.get("sales_order")
        if not so:
            continue
        if so not in wo_by_so:
            wo_by_so[so] = []
        wo_by_so[so].append(w)

    jc_by_wo = {}
    for jc in job_cards:
        wo = jc.get("work_order")
        if not wo:
            continue
        if wo not in jc_by_wo:
            jc_by_wo[wo] = []
        jc_by_wo[wo].append(jc)

    se_by_wo = {}
    for se in stock_entries:
        wo = se.get("work_order")
        if not wo:
            continue
        if wo not in se_by_wo:
            se_by_wo[wo] = []
        se_by_wo[wo].append(se)

    rows = []
    for so in sales_orders:
        so_name = so.get("name")
        wos = wo_by_so.get(so_name, [])
        pp_set = sorted(list(set([w.get("production_plan") for w in wos if w.get("production_plan")])))

        wo_total = len(wos)
        wo_completed = len([w for w in wos if (w.get("status") or "").strip().lower() == "completed"])
        wo_qty_total = sum([to_float(w.get("qty")) for w in wos])
        wo_qty_done = sum([to_float(w.get("produced_qty")) for w in wos])
        wo_completion_pct = 0
        if wo_qty_total > 0:
            wo_completion_pct = (wo_qty_done / wo_qty_total) * 100

        jc_total = 0
        jc_completed = 0
        se_count = 0
        wo_details = []
        jc_details = []
        for w in wos:
            wo_name = w.get("name")
            jc_list = jc_by_wo.get(wo_name, [])
            se_list = se_by_wo.get(wo_name, [])
            jc_total += len(jc_list)
            jc_completed += len([j for j in jc_list if (j.get("status") or "").strip().lower() == "completed"])
            se_count += len(se_list)
            wo_qty = to_float(w.get("qty"))
            wo_done = to_float(w.get("produced_qty"))
            wo_pct = 0
            if wo_qty > 0:
                wo_pct = (wo_done / wo_qty) * 100
            wo_details.append({
                "name": wo_name,
                "status": w.get("status"),
                "qty": wo_qty,
                "produced_qty": wo_done,
                "completion_pct": round(wo_pct, 2),
            })
            for j in jc_list:
                jc_details.append({
                    "name": j.get("name"),
                    "work_order": wo_name,
                    "status": j.get("status"),
                    "operation": j.get("operation"),
                })

        rows.append({
            "sales_order": so_name,
            "date": so.get("transaction_date"),
            "customer": so.get("customer"),
            "so_status": so.get("status"),
            "delivery_status": so.get("delivery_status"),
            "billing_status": so.get("billing_status"),
            "production_plans": ", ".join(pp_set),
            "work_order_total": wo_total,
            "work_order_completed": wo_completed,
            "job_card_total": jc_total,
            "job_card_completed": jc_completed,
            "stock_entry_count": se_count,
            "wo_completion_pct": round(wo_completion_pct, 2),
            "wo_details": wo_details,
            "jc_details": jc_details,
        })

    return rows


if action in ("start_job_card", "update_production", "complete_job_card"):
    employees = normalize_employees(args.get("employees"))
    if not employees:
