    # Get job card names
    jc_names = [jc.get("name") for jc in job_cards if jc.get("name")]

    # Fetch time logs to get actual start times
    employee_time_logs = []
    if jc_names:
        def chunks_list(lst, n=1000):
            for i in range(0, len(lst), n):
                yield lst[i:i+n]

        for chunk in chunks_list(jc_names):
            try:
                time_logs = frappe.get_all(
