            "work_order_item": wo_info.get("item_name") or wo_info.get("production_item"),
            "work_order_qty": wo_info.get("qty") or 0,
            "work_order_produced": wo_info.get("produced_qty") or 0,
            "work_order_status": wo_info.get("status"),
            "sales_order": wo_info.get("sales_order") or "",
            "production_plan": wo_info.get("production_plan") or "",
            "posting_date": jc.get("posting_date"),
            "company": jc.get("company") or "",
        })

    status_priority = {
        "Work In Progress": 1,
        "Material Transferred": 2,
        "Open": 3,
        "Pending": 4,
        "Completed": 5,
        "On Hold": 6,
        "Cancelled": 7,
    }

    result.sort(key=lambda x: (
        status_priority.get(x.get("status"), 99),
        x.get("start_time") or "",
        x.get("job_card") or ""
    ))

    frappe.response["message"] = {
        "job_cards": result,
        "count": len(result),
        "timestamp": frappe.utils.now(),
    }

# production_dashboard_api (v3 optimized)
# Script Type: API
# API Method: production_dashboard_api
#
# Key upgrades:
# - Safe caps via limit_* args to protect performance on large ranges
# - Avoid per-document get_doc; batch fetch time logs
# - Return distincts for slicers

args = frappe.form_dict

from_date = args.get("from_date")
to_date = args.get("to_date")
company = args.get("company")
production_item = args.get("production_item")
status = args.get("status")
