# Performance caps (frontend sets defaults; you can adjust here)
limit_work_orders = int(args.get("limit_work_orders") or 15000)
limit_job_cards   = int(args.get("limit_job_cards") or 20000)
limit_time_logs   = int(args.get("limit_time_logs") or 50000)

filters = {}
if from_date and to_date:
