            process_size = normalize_param(parts[4]) or "No Size"
            qty_index = 5
            rate_index = 6
        if len(parts) >= 8:
            sales_order = normalize_param(parts[7])
        qty = max(round2(parts[qty_index]), 0.0)
        rate = max(round2(parts[rate_index]), 0.0)
        amount = round2(qty * rate)
        if qty <= 0:
            continue
